{
  "query": "query GetContact($uuid: ID!) { contacts { contact(uuid: $uuid) { uuid firstName lastName email title company { uuid name } } } }",
  "variables": { "uuid": "{{contactUuid}}" }
}

{
  "query": "query ListContacts($query: VQLQueryInput) { contacts { contacts(query: $query) { items { uuid firstName lastName email title } pageInfo { total limit offset hasNext hasPrevious } } } }",
  "variables": { "query": { "limit": 20, "offset": 0 } }
}

{
  "query": "query ContactVql($query: VQLQueryInput!) { contacts { contactQuery(query: $query) { items { uuid firstName lastName email } pageInfo { total limit offset hasNext hasPrevious } } } }",
  "variables": { "query": { "limit": 20, "offset": 0 } }
}

{
  "query": "query ContactFilters { contacts { filters { items { filterKey filterType displayName key } } } } }",
  "variables": {}
}

{
  "query": "query ContactFilterData($input: ContactFilterDataInput!) { contacts { filterData(input: $input) { items { value displayValue count } total } } }",
  "variables": { "input": { "filterKey": "industry", "limit": 20 } }
}

{
  "query": "mutation CreateContact($input: CreateContactInput!) { contacts { createContact(input: $input) { uuid firstName lastName email title } } }",
  "variables": {
    "input": {
      "firstName": "John",
      "lastName": "Doe",
      "email": "john.doe@example.com",
      "title": "Engineer",
      "companyUuid": "{{companyUuid}}"
    }
  }
}

{
  "query": "mutation UpdateContact($uuid: ID!, $input: UpdateContactInput!) { contacts { updateContact(uuid: $uuid, input: $input) { uuid firstName lastName email title } } }",
  "variables": { "uuid": "{{contactUuid}}", "input": { "title": "Senior Engineer" } }
}

{
  "query": "mutation BatchCreate($input: BatchCreateContactsInput!) { contacts { batchCreateContacts(input: $input) { uuid firstName lastName email } } }",
  "variables": {
    "input": {
      "contacts": [
        { "firstName": "A", "lastName": "One", "email": "a@example.com" },
        { "firstName": "B", "lastName": "Two", "email": "b@example.com" }
      ]
    }
  }
}

{
  "query": "mutation ExportContacts($input: CreateContact360ExportInput!) { contacts { exportContacts(input: $input) { jobId jobType status } } }",
  "variables": {
    "input": {
      "outputPrefix": "contacts_export",
      "service": "contact",
      "vql": {},
      "pageSize": 500
    }
  }
}

{
  "query": "mutation ImportContacts($input: CreateContact360ImportInput!) { contacts { importContacts(input: $input) { jobId jobType status } } }",
  "variables": {
    "input": {
      "s3Bucket": "{{s3Bucket}}",
      "s3Key": "{{fileKey}}",
      "outputPrefix": "imports/"
    }
  }
}
